import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input from an untrusted source
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encode user input before including it in the output HTML
        String encodedInput = "";
        try {
            encodedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.out.println("Encoding error: " + e.getMessage());
        }

        String outputHtml = "<div>" + encodedInput + "</div>";

        System.out.println(outputHtml);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
